# Scan-AppData.ps1
# แสกน AppData เพื่อหาไฟล์ใหญ่/ซ้ำ/ลบได้

param(
    [string]$Path = "$env:USERPROFILE\AppData\Local",
    [int]$Top = 20
)

Write-Host "=== Scanning $Path ===" -ForegroundColor Cyan

# 1. Top 20 largest files
Write-Host "`n=== Top $Top Largest Files ===" -ForegroundColor Yellow
Get-ChildItem -Path $Path -Recurse -File -ErrorAction SilentlyContinue |
    Sort-Object Length -Descending |
    Select-Object -First $Top |
    ForEach-Object {
        $size = if ($_.Length -gt 1GB) { "{0:N2} GB" -f ($_.Length / 1GB) }
                elseif ($_.Length -gt 1MB) { "{0:N2} MB" -f ($_.Length / 1MB) }
                else { "{0:N2} KB" -f ($_.Length / 1KB) }
        Write-Host "$size  $($_.FullName)"
    }

# 2. Large folders summary
Write-Host "`n=== Large Folders ===" -ForegroundColor Yellow
Get-ChildItem -Path $Path -Directory -ErrorAction SilentlyContinue |
    ForEach-Object {
        $size = (Get-ChildItem -Path $_.FullName -Recurse -ErrorAction SilentlyContinue | Measure-Object -Property Length -Sum).Sum
        [PSCustomObject]@{
            Folder = $_.Name
            SizeMB = [math]::Round($size / 1MB, 2)
            Path = $_.FullName
        }
    } |
    Sort-Object SizeMB -Descending |
    Select-Object -First 20 |
    ForEach-Object {
        Write-Host "$($_.SizeMB) MB  $($_.Folder)"
    }

# 3. Cache/Temp folders (likely deletable)
Write-Host "`n=== Cache/Temp Folders (Safe to Delete) ===" -ForegroundColor Yellow
$cachePatterns = @("Cache", "Temp", "cache", "temp", "*Cache*", "*cache*", "*Temp*")
foreach ($pattern in $cachePatterns) {
    Get-ChildItem -Path $Path -Directory -Filter $pattern -ErrorAction SilentlyContinue |
        ForEach-Object {
            $size = (Get-ChildItem -Path $_.FullName -Recurse -ErrorAction SilentlyContinue | Measure-Object -Property Length -Sum).Sum
            $sizeMB = [math]::Round($size / 1MB, 2)
            if ($sizeMB -gt 10) {
                Write-Host "$sizeMB MB  $($_.FullName)" -ForegroundColor Green
            }
        }
}

Write-Host "`n=== Done ===" -ForegroundColor Cyan

