import os

path = '/mnt/c/Users/Apinan/AppData/Local'
results = []
try:
    for item in os.listdir(path):
        full = os.path.join(path, item)
        if os.path.isdir(full):
            try:
                total = sum(os.path.getsize(os.path.join(dp, f)) for dp, dn, fn in os.walk(full) for f in fn)
                results.append((item, total / 1024 / 1024))
            except:
                pass
except: pass

results.sort(key=lambda x: x[1], reverse=True)
for name, size in results[:20]:
    print(f'{size:,.0f} MB  {name}')
" 2>/dev/null

